1	<script lang="ts">
2		import type { PageData } from './$types';
3		import { goto } from '$app/navigation';
4		import { resolve } from '$app/paths';
5		import { Search } from 'lucide-svelte';
6		import { createClient } from '$lib/gql/client';
7		import FilterChip from '$lib/components/FilterChip.svelte';
8		import {
9			ARTIFACTS_QUERY,
10			PAGE_SIZE,
11			SORT_OPTIONS,
12			STALENESS_OPTIONS,
13			DEFAULT_SORT,
14			type ArtifactSort,
15			type Staleness
16		} from './+page';
17		import type { ArtifactEdge, ArtifactConnection, PageInfo } from './+page';
18		import { writeState } from '$lib/urlState';
19		import {
20			GROUP_BY_OPTIONS,
21			groupItems,
22			groupCountLabel,
23			axisAvailable,
24			GROUP_BY_LABELS,
25			type GroupBy
26		} from './grouping';
27		import { readPersistedGroupBy, writePersistedGroupBy } from './persistence';
28		import { createRequestSequence, runLatest } from './searchFetcher';
29	
30		let { data }: { data: PageData } = $props();
31	
32		let allEdges = $state<ArtifactEdge[]>(data.artifacts.edges);
33		let pageInfo = $state<PageInfo>(data.artifacts.pageInfo);
34		let loading = $state(false);
35	
36		$effect(() => {
37			allEdges = data.artifacts.edges;
38			pageInfo = data.artifacts.pageInfo;
39		});
40	
41		let q = $state(data.q);
42		let groupBy = $state<GroupBy>(data.groupBy);
43		let pendingStoredGroupBy: GroupBy | null | undefined = undefined;
44	
45		// sessionStorage persistence with stable keys (per project).
46		const SS_KEY_MEDIA_TYPE = `artifacts:mediaType:${data.projectId}`;
47	
48		$effect(() => {
49			if (typeof sessionStorage === 'undefined') return;
50			try {
51				writePersistedGroupBy(sessionStorage, data.projectId, groupBy);
52				if (data.mediaType) sessionStorage.setItem(SS_KEY_MEDIA_TYPE, data.mediaType);
53				else sessionStorage.removeItem(SS_KEY_MEDIA_TYPE);
54			} catch {
55				// sessionStorage may be unavailable (private mode, SSR); ignore.
56			}
57		});
58	
59		$effect(() => {
60			if (data.hasGroupByParam || pendingStoredGroupBy === null) return;
61			if (pendingStoredGroupBy === undefined) {
62				if (typeof sessionStorage === 'undefined') {
63					pendingStoredGroupBy = null;
64					return;
65				}
66				try {
67					pendingStoredGroupBy = readPersistedGroupBy(sessionStorage, data.projectId);
68				} catch {
69					pendingStoredGroupBy = null;
70					return;
71				}
72			}
73			if (pendingStoredGroupBy === null) return;
74			if (pendingStoredGroupBy === 'workflowStage' && !workflowStageAxisAvailable) return;
75			if (pendingStoredGroupBy !== groupBy) {
76				groupBy = pendingStoredGroupBy;
77				navigateWith({ groupBy: pendingStoredGroupBy }, { replace: true });
78			}
79			pendingStoredGroupBy = null;
80		});
81	
82		// Server-side search: q is sent to the backend so results are correct
83		// across all pages, not just the loaded edges.
84		const filtered = $derived(allEdges);
85		const workflowStageAxisAvailable = $derived(axisAvailable(filtered.map((e) => e.node.path)));
86		const effectiveGroupBy = $derived(
87			groupBy === 'workflowStage' && !workflowStageAxisAvailable ? 'folder' : groupBy
88		);
89		const visibleGroupByOptions = $derived(
90			GROUP_BY_OPTIONS.filter((opt) => opt.value !== 'workflowStage' || workflowStageAxisAvailable)
91		);
92	
93		const groups = $derived(
94			groupItems(
95				filtered.map((e) => ({ ...e, path: e.node.path, mediaType: e.node.mediaType })),
96				effectiveGroupBy
97			)
98		);
99	
100		let searchDebounce: ReturnType<typeof setTimeout> | undefined;
101		const fetchSeq = createRequestSequence();
102	
103		function navigateWith(patch: Parameters<typeof writeState>[1], opts?: { replace?: boolean }) {
104			const url = new URL(window.location.href);
105			const params = writeState(url.searchParams, patch);
106			const search = params.toString();
107			// goto() re-runs load(), which resets allEdges/pageInfo (cursor) via the
108			// $effect bound to `data` — satisfying the "param change resets cursor" AC.
109			void goto(
110				resolve(
111					`/nodes/${data.nodeId}/projects/${data.projectId}/artifacts${search ? `?${search}` : ''}`
112				),
113				{ replaceState: opts?.replace ?? false, keepFocus: true, noScroll: true }
114			);
115		}
116	
117		function onSearchInput(e: Event) {
118			q = (e.target as HTMLInputElement).value;
119			clearTimeout(searchDebounce);
120			// Invalidate any in-flight loadMore so its (stale) results don't get
121			// appended on top of fresh search results when the goto() reload lands.
122			fetchSeq.invalidate();
123			searchDebounce = setTimeout(() => {
124				navigateWith({ q }, { replace: true });
125			}, 200);
126		}
127	
128		function selectGroupBy(next: GroupBy) {
129			pendingStoredGroupBy = null;
130			groupBy = next;
131			navigateWith({ groupBy: next });
132		}
133	
134		function selectSort(next: ArtifactSort) {
135			navigateWith({ sort: next === DEFAULT_SORT ? null : next });
136		}
137	
138		function selectStaleness(next: Staleness | null) {
139			// Toggle off if user re-clicks the active chip.
140			const value = next && next === data.staleness ? null : next;
141			navigateWith({ staleness: value });
142		}
143	
144		// Phase axis: HELIX phases sourced from path prefix docs/helix/NN-*/.
145		// The PHASE_OPTIONS list mirrors the canonical numbered phases the project uses.
146		const PHASE_OPTIONS: { label: string; value: string }[] = [
147			{ label: '01 Frame', value: '01-frame' },
148			{ label: '02 Design', value: '02-design' },
149			{ label: '03 Test', value: '03-test' },
150			{ label: '04 Build', value: '04-build' },
151			{ label: '05 Deploy', value: '05-deploy' },
152			{ label: '06 Iterate', value: '06-iterate' }
153		];
154	
155		function selectPhase(next: string | null) {
156			const value = next && next === data.phase ? null : next;
157			navigateWith({ phase: value });
158		}
159	
160		// Prefix axis: id-prefix segment (ADR|SD|FEAT|US|RSCH|PRD).
161		// Multi-select OR semantics — clicking toggles membership.
162		const PREFIX_OPTIONS = ['ADR', 'SD', 'FEAT', 'US', 'RSCH', 'PRD'] as const;
163	
164		function togglePrefix(p: string) {
165			const cur = data.prefix ?? [];
166			const next = cur.includes(p) ? cur.filter((x) => x !== p) : [...cur, p];
167			navigateWith({ prefix: next });
168		}
169	
170		const MEDIA_TYPES: { label: string; value: string | null }[] = [
171			{ label: 'All', value: null },
172			{ label: 'Markdown', value: 'text/markdown' },
173			{ label: 'SVG', value: 'image/svg+xml' },
174			{ label: 'Image', value: 'image/*' },
175			{ label: 'PDF', value: 'application/pdf' },
176			{ label: 'Excalidraw', value: 'application/vnd.excalidraw+json' },
177			{ label: 'Unknown', value: 'unknown' }
178		];
179	
180		function selectMediaType(mediaType: string | null) {
181			navigateWith({ mediaType, q });
182		}
183	
184		function openGraph() {
185			void goto(resolve(`/nodes/${data.nodeId}/projects/${data.projectId}/graph`));
186		}
187	
188		function viewInGraph(artifactId: string) {
189			const docId = artifactId.replace(/^doc:/, '');
190			void goto(
191				resolve(
192					`/nodes/${data.nodeId}/projects/${data.projectId}/graph?highlight=${encodeURIComponent(docId)}`
193				)
194			);
195		}
196	
197		function openArtifact(id: string) {
198			// Pass current filter/search state as a "back" param so the detail page
199			// can return to the same filtered list state.
200			const listUrl = new URL(window.location.href);
201			const backHref = listUrl.pathname + listUrl.search;
202			const backParam =
203				backHref !== `/nodes/${data.nodeId}/projects/${data.projectId}/artifacts`
204					? `?back=${encodeURIComponent(backHref)}`
205					: '';
206			void goto(
207				resolve(
208					`/nodes/${data.nodeId}/projects/${data.projectId}/artifacts/${encodeURIComponent(id)}${backParam}`
209				)
210			);
211		}
212	
213		async function loadMore() {
214			if (!pageInfo.hasNextPage || loading) return;
215			loading = true;
216			try {
217				const client = createClient();
218				const outcome = await runLatest(fetchSeq, () =>
219					client.request<{ artifacts: ArtifactConnection }>(ARTIFACTS_QUERY, {
220						projectID: data.projectId,
221						first: PAGE_SIZE,
222						after: pageInfo.endCursor,
223						mediaType: data.mediaType ?? undefined,
224						search: q ? q : undefined,
225						sort: data.sort,
226						staleness: data.staleness ?? undefined,
227						phase: data.phase ?? undefined,
228						prefix: data.prefix && data.prefix.length > 0 ? data.prefix : undefined
229					})
230				);
231				if (outcome.stale) return;
232				allEdges = [...allEdges, ...outcome.value.artifacts.edges];
233				pageInfo = outcome.value.artifacts.pageInfo;
234			} finally {
235				loading = false;
236			}
237		}
238	
239		// Render a server-supplied snippet to HTML. The resolver wraps the matched
240		// substring in markdown emphasis ("**…**"); we escape the rest and convert
241		// the marker pairs to <mark> for visual highlighting. Only the first
242		// matching pair is highlighted (resolver emits a single match per snippet).
243		function escapeHtml(s: string): string {
244			return s
245				.replace(/&/g, '&amp;')
246				.replace(/</g, '&lt;')
247				.replace(/>/g, '&gt;')
248				.replace(/"/g, '&quot;')
249				.replace(/'/g, '&#39;');
250		}
251		function renderSnippet(snippet: string): string {
252			const escaped = escapeHtml(snippet);
253			return escaped.replace(
254				/\*\*([\s\S]+?)\*\*/,
255				'<mark class="rounded bg-yellow-200 px-0.5 text-fg-ink dark:bg-yellow-500/40 dark:text-dark-fg-ink">$1</mark>'
256			);
257		}
258	
259		function stalenessBadge(staleness: string): { label: string; cls: string } {
260			switch (staleness) {
261				case 'fresh':
262					return {
263						label: 'fresh',
264						cls: 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400'
265					};
266				case 'stale':
267					return {
268						label: 'stale',
269						cls: 'bg-amber-100 text-amber-800 dark:bg-amber-900/30 dark:text-amber-400'
270					};
271				case 'missing':
272					return {
273						label: 'missing',
274						cls: 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400'
275					};
276				default:
277					return {
278						label: staleness,
279						cls: 'bg-bg-surface text-fg-muted dark:bg-dark-bg-surface dark:text-dark-fg-muted'
280					};
281			}
282		}
283	</script>
284	
285	<div class="space-y-4">
286		<div class="flex items-center justify-between">
287			<h1 class="text-headline-md font-headline-md text-fg-ink dark:text-dark-fg-ink">Artifacts</h1>
288			<div class="flex items-center gap-3">
289				<span class="text-body-sm text-fg-muted dark:text-dark-fg-muted">
290					{data.artifacts.totalCount} total
291				</span>
292				<button
293					onclick={openGraph}
294					class="border-border-line bg-bg-surface text-body-sm text-fg-muted hover:bg-bg-elevated hover:text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-muted dark:hover:bg-dark-bg-elevated dark:hover:text-dark-fg-ink rounded border px-3 py-1.5"
295				>
296					Open Graph
297				</button>
298			</div>
299		</div>
300	
301		<!-- Filter chips -->
302		<div class="flex flex-wrap gap-2" data-testid="media-type-chips">
303			{#each MEDIA_TYPES as chip (chip.label)}
304				<FilterChip
305					label={chip.label}
306					active={chip.value === data.mediaType}
307					onclick={() => selectMediaType(chip.value)}
308				/>
309			{/each}
310		</div>
311	
312		<!-- Staleness filter chips -->
313		<div class="flex flex-wrap gap-2" data-testid="staleness-chips">
314			<span
315				class="font-label-caps text-label-caps text-fg-muted dark:text-dark-fg-muted self-center uppercase"
316				>Staleness</span
317			>
318			{#each STALENESS_OPTIONS as value (value)}
319				{@const active = data.staleness === value}
320				<FilterChip
321					label={value}
322					testid="staleness-chip-{value}"
323					{active}
324					ariaPressed={active}
325					onclick={() => selectStaleness(value)}
326				/>
327			{/each}
328			{#if data.staleness}
329				<FilterChip
330					label="Clear"
331					testid="staleness-chip-clear"
332					clear
333					onclick={() => selectStaleness(null)}
334				/>
335			{/if}
336		</div>
337	
338		<!-- Phase filter chips (HELIX phase, sourced from docs/helix/NN-*/ path prefix) -->
339		<div class="flex flex-wrap gap-2" data-testid="phase-chips">
340			<span
341				class="font-label-caps text-label-caps text-fg-muted dark:text-dark-fg-muted self-center uppercase"
342				>Phase</span
343			>
344			{#each PHASE_OPTIONS as opt (opt.value)}
345				{@const active = data.phase === opt.value}
346				<FilterChip
347					label={opt.label}
348					testid="phase-chip-{opt.value}"
349					{active}
350					ariaPressed={active}
351					onclick={() => selectPhase(opt.value)}
352				/>
353			{/each}
354			{#if data.phase}
355				<FilterChip label="Clear" testid="phase-chip-clear" clear onclick={() => selectPhase(null)} />
356			{/if}
357		</div>
358	
359		<!-- Prefix filter chips (id-prefix segment, multi-select OR) -->
360		<div class="flex flex-wrap gap-2" data-testid="prefix-chips">
361			<span
362				class="font-label-caps text-label-caps text-fg-muted dark:text-dark-fg-muted self-center uppercase"
363				>Prefix</span
364			>
365			{#each PREFIX_OPTIONS as p (p)}
366				{@const active = (data.prefix ?? []).includes(p)}
367				<FilterChip
368					label={p}
369					testid="prefix-chip-{p}"
370					{active}
371					ariaPressed={active}
372					onclick={() => togglePrefix(p)}
373				/>
374			{/each}
375			{#if data.prefix && data.prefix.length > 0}
376				<FilterChip
377					label="Clear"
378					testid="prefix-chip-clear"
379					clear
380					onclick={() => navigateWith({ prefix: [] })}
381				/>
382			{/if}
383		</div>
384	
385		<!-- Search bar + group-by selector -->
386		<div class="flex items-center gap-3">
387			<div class="relative flex-1">
388				<Search
389					class="text-fg-muted dark:text-dark-fg-muted pointer-events-none absolute top-1/2 left-3 h-4 w-4 -translate-y-1/2"
390				/>
391				<input
392					type="search"
393					placeholder="Search title or path…"
394					value={q}
395					oninput={onSearchInput}
396					class="border-border-line bg-bg-surface text-body-sm text-fg-ink placeholder:text-fg-muted focus:ring-accent-lever dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-ink dark:placeholder:text-dark-fg-muted dark:focus:ring-dark-accent-lever w-full rounded border py-2 pr-3 pl-9 focus:ring-1 focus:outline-none"
397				/>
398			</div>
399			<label class="text-body-sm text-fg-muted dark:text-dark-fg-muted flex items-center gap-2">
400				<span>Sort by</span>
401				<select
402					aria-label="Sort by"
403					data-testid="sort-select"
404					value={data.sort}
405					onchange={(e) => selectSort((e.target as HTMLSelectElement).value as ArtifactSort)}
406					class="border-border-line bg-bg-surface text-body-sm text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-ink rounded border px-2 py-1.5"
407				>
408					{#each SORT_OPTIONS as opt (opt.value)}
409						<option value={opt.value}>{opt.label}</option>
410					{/each}
411				</select>
412			</label>
413			<label class="text-body-sm text-fg-muted dark:text-dark-fg-muted flex items-center gap-2">
414				<span>Group by</span>
415				<select
416					aria-label="Group by"
417					value={effectiveGroupBy}
418					onchange={(e) => selectGroupBy((e.target as HTMLSelectElement).value as GroupBy)}
419					class="border-border-line bg-bg-surface text-body-sm text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-ink rounded border px-2 py-1.5"
420				>
421					{#each visibleGroupByOptions as opt (opt.value)}
422						<option value={opt.value}>{opt.label}</option>
423					{/each}
424				</select>
425			</label>
426		</div>
427	
428		<!-- Table -->
429		<div class="border-border-line dark:border-dark-border-line overflow-hidden border">
430			<table class="w-full text-sm">
431				<thead>
432					<tr
433						class="border-border-line bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-surface border-b"
434					>
435						<th
436							class="font-label-caps text-label-caps text-fg-muted dark:text-dark-fg-muted px-4 py-3 text-left tracking-wide uppercase"
437							>Title</th
438						>
439						<th
440							class="font-label-caps text-label-caps text-fg-muted dark:text-dark-fg-muted px-4 py-3 text-left tracking-wide uppercase"
441							>Path</th
442						>
443						<th
444							class="font-label-caps text-label-caps text-fg-muted dark:text-dark-fg-muted px-4 py-3 text-left tracking-wide uppercase"
445							>Type</th
446						>
447						<th
448							class="font-label-caps text-label-caps text-fg-muted dark:text-dark-fg-muted px-4 py-3 text-left tracking-wide uppercase"
449							>Staleness</th
450						>
451						<th class="px-4 py-3"></th>
452					</tr>
453				</thead>
454				{#each groups as group (group.key)}
455					<tbody role="rowgroup" aria-label="{GROUP_BY_LABELS[effectiveGroupBy]}: {group.key}">
456						<tr class="bg-bg-elevated dark:bg-dark-bg-elevated">
457							<th
458								colspan="5"
459								scope="rowgroup"
460								role="rowheader"
461								class="font-label-caps text-label-caps text-fg-muted dark:text-dark-fg-muted px-4 py-2 text-left tracking-wide uppercase"
462							>
463								{group.key}
464								<span class="text-fg-muted dark:text-dark-fg-muted ml-2 normal-case">
465									({groupCountLabel(group.items.length, filtered.length, pageInfo.hasNextPage)})
466								</span>
467							</th>
468						</tr>
469						{#each group.items as edge (edge.cursor)}
