471							<tr
472								onclick={() => openArtifact(edge.node.id)}
473								class="border-border-line hover:bg-bg-surface dark:border-dark-border-line dark:hover:bg-dark-bg-surface cursor-pointer border-b last:border-0"
474							>
475								<td class="text-fg-ink dark:text-dark-fg-ink px-4 py-3">
476									{edge.node.title}
477								</td>
478								<td
479									class="font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted px-4 py-3"
480								>
481									{edge.node.path}
482								</td>
483								<td
484									class="font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted px-4 py-3"
485								>
486									{edge.node.mediaType}
487								</td>
488								<td class="px-4 py-3">
489									<span
490										class="font-label-caps text-label-caps inline-block rounded-full px-2 py-0.5 uppercase {badge.cls}"
