492										{badge.label}
493									</span>
494								</td>
495								<td class="px-4 py-3">
496									<button
497										onclick={(e) => {
498											e.stopPropagation();
499											viewInGraph(edge.node.id);
500										}}
501										class="border-border-line bg-bg-surface font-label-caps text-label-caps text-fg-muted hover:bg-bg-elevated hover:text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-muted dark:hover:bg-dark-bg-elevated dark:hover:text-dark-fg-ink rounded border px-2 py-0.5 uppercase"
502									>
503										View in Graph
504									</button>
505								</td>
506							</tr>
507							{#if edge.snippet}
508								<tr
509									data-testid="artifact-snippet-{edge.node.id}"
510									onclick={() => openArtifact(edge.node.id)}
511									class="border-border-line hover:bg-bg-surface dark:border-dark-border-line dark:hover:bg-dark-bg-surface cursor-pointer border-b last:border-0"
512								>
513									<td
514										colspan="5"
515										class="text-body-sm text-fg-muted dark:text-dark-fg-muted px-4 pb-3"
516									>
517										<!-- eslint-disable-next-line svelte/no-at-html-tags -->
518										<span class="block leading-snug">{@html renderSnippet(edge.snippet)}</span>
519									</td>
520								</tr>
521							{/if}
522						{/each}
523					</tbody>
524				{/each}
525				{#if filtered.length === 0}
526					<tbody>
527						<tr>
528							<td
529								colspan="5"
530								class="text-body-sm text-fg-muted dark:text-dark-fg-muted px-4 py-8 text-center"
531							>
532								No artifacts found.
533							</td>
534						</tr>
535					</tbody>
536				{/if}
537			</table>
538		</div>
539	
540		<!-- Load more -->
541		{#if pageInfo.hasNextPage}
542			<div class="flex justify-center">
543				<button
