1	/**
2	 * Monotonic request sequence used to drop stale responses on race.
3	 *
4	 * Each `next()` call issues a fresh token and marks it as the latest.
5	 * `isCurrent(token)` returns true only if no newer token has been issued
6	 * (and the sequence has not been explicitly invalidated). `invalidate()`
7	 * drops all in-flight tokens without issuing a new one — useful when an
8	 * upstream input (e.g. the search query) changes and any pending response
9	 * should be discarded.
10	 */
11	export interface RequestSequence {
12		next(): number
13		isCurrent(token: number): boolean
14		invalidate(): void
15	}
16	
17	export function createRequestSequence(): RequestSequence {
18		let issued = 0
19		let latest = 0
20		return {
21			next() {
22				issued += 1
23				latest = issued
24				return issued
25			},
26			isCurrent(token: number) {
27				return token === latest && token !== 0
28			},
29			invalidate() {
30				latest = 0
31			}
32		}
33	}
34	
35	/**
36	 * Run an async fn under a request sequence. Returns the result if the
37	 * call is still the latest when it resolves; otherwise returns
38	 * `{ stale: true }`. Errors propagate; stale-after-error is silently
39	 * swallowed so callers do not surface exceptions from canceled requests.
40	 */
41	export async function runLatest<T>(
42		seq: RequestSequence,
43		fn: () => Promise<T>
44	): Promise<{ stale: false; value: T } | { stale: true }> {
45		const token = seq.next()
46		try {
47			const value = await fn()
48			if (!seq.isCurrent(token)) return { stale: true }
49			return { stale: false, value }
50		} catch (err) {
51			if (!seq.isCurrent(token)) return { stale: true }
52			throw err
53		}
54	}
