269	function isGraphQLEndpoint(input: Parameters<typeof globalThis.fetch>[0]): boolean {
270		if (typeof input === 'string') {
271			return new URL(input, globalThis.location?.href ?? 'http://localhost').pathname === '/graphql';
272		}
273		if (input instanceof URL) {
274			return input.pathname === '/graphql';
275		}
276		return new URL(input.url).pathname === '/graphql';
277	}
278	
279	async function requestBodyText(
280		input: Parameters<typeof globalThis.fetch>[0],
281		init?: Parameters<typeof globalThis.fetch>[1]
282	): Promise<string | null> {
283		if (typeof init?.body === 'string') {
284			return init.body;
285		}
286		if (input instanceof Request) {
287			return input.clone().text();
288		}
289		return null;
290	}
291	
292	function fallbackGraphQLResponse(data: object): Response {
293		return new Response(JSON.stringify({ data }), {
294			status: 200,
295			headers: { 'content-type': 'application/json' }
296		});
297	}
298	
299	function delegateInputFor(
300		input: Parameters<typeof globalThis.fetch>[0]
301	): Parameters<typeof globalThis.fetch>[0] {
302		if (typeof window === 'undefined' || !isGraphQLEndpoint(input)) {
303			return input;
304		}
305		if (typeof input === 'string' || input instanceof URL) {
306			return '/graphql';
307		}
308		return input;
309	}
310	
311	function withStaticPreviewFallback(fetchFn?: typeof globalThis.fetch): typeof globalThis.fetch {
312		const delegate = fetchFn ?? globalThis.fetch;
313		return async (input, init) => {
314			const delegateInput = delegateInputFor(input);
315			const response = await delegate(delegateInput, init);
316			if (response.status !== 404 || !isGraphQLEndpoint(input)) {
317				return response;
318			}
319	
320			const bodyText = await requestBodyText(input, init);
321			if (!bodyText) {
322				return response;
323			}
324	
325			let body: { query?: string };
326			try {
327				body = JSON.parse(bodyText) as { query?: string };
328			} catch {
329				return response;
330			}
331	
332			const data = body.query ? fallbackDataForQuery(body.query) : null;
333			return data ? fallbackGraphQLResponse(data) : response;
334		};
335	}
336	
337	/**
338	 * Creates a GraphQL HTTP client for queries and mutations.
339	 *
340	 * Pass the SvelteKit-provided `fetch` in load functions so requests
341	 * respect SvelteKit's SSR/CSR fetch instrumentation.
342	 */
343	export function createClient(fetchFn?: typeof globalThis.fetch): GraphQLClient {
344		const url =
345			typeof window !== 'undefined' ? new URL('/graphql', window.location.href).href : '/graphql';
346		return new GraphQLClient(url, { fetch: withStaticPreviewFallback(fetchFn) });
347	}
