5	const DOCUMENT_BY_PATH = gql`
6		query DocumentByPath($path: String!) {
7			documentByPath(path: $path) {
8				id
9				path
10				title
11				content
12				dependsOn
13				dependents
14			}
15		}
16	`
17	
18	const DOC_GRAPH_QUERY = gql`
19		query DocGraphForSearch {
20			docGraph {
21				documents {
22					id
23					path
24					title
25				}
26			}
27		}
28	`
29	
30	interface DocumentByPathResult {
31		documentByPath: {
32			id: string
33			path: string
34			title: string
35			content: string
36			dependsOn: string[]
37			dependents: string[]
38		} | null
39	}
40	
41	interface DocGraphForSearchResult {
42		docGraph: {
43			documents: { id: string; path: string; title: string }[]
44		}
45	}
46	
47	export const load: PageLoad = async ({ params, fetch }) => {
48		const client = createClient(fetch as unknown as typeof globalThis.fetch)
49		const [docResult, graphResult] = await Promise.allSettled([
50			client.request<DocumentByPathResult>(DOCUMENT_BY_PATH, { path: params.path }),
51			client.request<DocGraphForSearchResult>(DOC_GRAPH_QUERY)
52		])
53	
54		const doc = docResult.status === 'fulfilled' ? docResult.value.documentByPath : null
55		const allDocuments =
56			graphResult.status === 'fulfilled' ? graphResult.value.docGraph.documents : []
57	
58		if (!doc) {
59			return { path: params.path, content: null, dependsOn: [], dependents: [], title: '', allDocuments }
60		}
61	
62		return {
63			path: doc.path,
64			title: doc.title,
65			content: doc.content,
66			dependsOn: doc.dependsOn,
67			dependents: doc.dependents,
68			allDocuments
69		}
70	}
