7	// folderOf("docs/helix/01-frame/prd.md") => "docs/helix/01-frame"
8	// folderOf("README.md") => "/"
9	const FOLDER_RE = /^(.*)\/[^/]+$/;
10	export function folderOf(path: string): string {
11		const m = path.match(FOLDER_RE);
12		if (!m) return '/';
13		return m[1] || '/';
