18	// Workflow stage derivation. Matches the canonical HELIX-style numbered
19	// stage segment (e.g. 01-frame, 02-design) anywhere in the path. Returns
20	// the bare stage name lowercased, or null when no stage segment is found.
21	const STAGE_RE = /(?:^|\/)\d{2}-([a-z][a-z0-9-]*)(?:\/|$)/i;
22	export function workflowStageOf(path: string): string | null {
23		const m = path.match(STAGE_RE);
24		return m ? m[1].toLowerCase() : null;
25	}
