27	// Whether the workflow-stage axis should be shown for the given paths.
28	// The axis is hidden when no artifact in view has a derivable stage.
29	export function axisAvailable(paths: Iterable<string>): boolean {
30		for (const p of paths) {
31			if (workflowStageOf(p) !== null) return true;
32		}
33		return false;
34	}
