36	export interface Groupable {
37		path: string;
38		mediaType: string;
39	}
40	
41	// Generic, project-neutral label for the workflow-stage axis.
42	export const WORKFLOW_STAGE_LABEL = 'Workflow stage';
43	
44	export const WORKFLOW_STAGE_FALLBACK_LABEL = 'Unstaged';
45	
46	export function groupKey(item: Groupable, by: GroupBy): string {
47		switch (by) {
48			case 'folder':
49				return folderOf(item.path);
50			case 'prefix':
51				return prefixOf(item.path);
52			case 'mediaType':
53				return item.mediaType || 'unknown';
54			case 'workflowStage':
55				return workflowStageOf(item.path) ?? WORKFLOW_STAGE_FALLBACK_LABEL;
56		}
57	}
58	
59	export function groupItems<T extends Groupable>(
60		items: T[],
61		by: GroupBy
62	): { key: string; items: T[] }[] {
63		const buckets = new Map<string, T[]>();
64		for (const it of items) {
65			const k = groupKey(it, by);
66			const arr = buckets.get(k);
67			if (arr) arr.push(it);
68			else buckets.set(k, [it]);
69		}
70		return Array.from(buckets.entries())
71			.sort(([a], [b]) => a.localeCompare(b))
72			.map(([key, items]) => ({ key, items }));
73	}
