7	export const ARTIFACTS_QUERY = gql`
8		query Artifacts(
9			$projectID: ID!
10			$first: Int
11			$after: String
12			$mediaType: String
13			$search: String
14			$sort: ArtifactSort
15			$staleness: String
16			$phase: String
17			$prefix: [String!]
18		) {
19			artifacts(
20				projectID: $projectID
21				first: $first
22				after: $after
23				mediaType: $mediaType
24				search: $search
25				sort: $sort
26				staleness: $staleness
27				phase: $phase
28				prefix: $prefix
29			) {
30				edges {
31					node {
32						id
33						path
34						title
35						mediaType
36						staleness
37					}
38					cursor
39					snippet
40				}
41				pageInfo {
42					hasNextPage
43					endCursor
44				}
45				totalCount
46			}
47		}
48	`;
