50	export interface ArtifactNode {
51		id: string;
52		path: string;
53		title: string;
54		mediaType: string;
55		staleness: string;
56	}
57	
58	export interface ArtifactEdge {
59		node: ArtifactNode;
60		cursor: string;
61		snippet?: string | null;
62	}
63	
64	export interface PageInfo {
65		hasNextPage: boolean;
66		endCursor: string | null;
67	}
68	
69	export interface ArtifactConnection {
70		edges: ArtifactEdge[];
71		pageInfo: PageInfo;
72		totalCount: number;
73	}
74	
75	interface ArtifactsResult {
76		artifacts: ArtifactConnection;
77	}
78	
79	export const PAGE_SIZE = 50;
80	
81	export const SORT_OPTIONS = [
82		{ value: 'PATH', label: 'Path' },
83		{ value: 'TITLE', label: 'Title' },
84		{ value: 'MODIFIED', label: 'Last modified' },
85		{ value: 'DEPS_COUNT', label: 'Dependency count' },
86		{ value: 'ID', label: 'ID' }
87	] as const;
88	
89	export type ArtifactSort = (typeof SORT_OPTIONS)[number]['value'];
90	export const DEFAULT_SORT: ArtifactSort = 'PATH';
91	
92	const SORT_VALUES = new Set(SORT_OPTIONS.map((o) => o.value));
93	
94	export function parseSort(raw: string | null): ArtifactSort {
95		return raw && SORT_VALUES.has(raw as ArtifactSort) ? (raw as ArtifactSort) : DEFAULT_SORT;
96	}
97	
98	export const STALENESS_OPTIONS = ['fresh', 'stale', 'missing'] as const;
99	export type Staleness = (typeof STALENESS_OPTIONS)[number];
100	const STALENESS_SET = new Set<string>(STALENESS_OPTIONS);
101	
102	export function parseStaleness(raw: string | null): Staleness | null {
103		return raw && STALENESS_SET.has(raw) ? (raw as Staleness) : null;
104	}
105	
106	export const load: PageLoad = async ({ params, url, fetch }) => {
107		const state = readState(url.searchParams);
108		const hasGroupByParam = url.searchParams.has('groupBy');
109		const mediaType = state.mediaType;
110		const q = state.q;
111		const groupBy: GroupBy = state.groupBy;
112		const sort = parseSort(state.sort);
113		const staleness = parseStaleness(state.staleness);
114		const phase = state.phase;
115		const prefix = state.prefix;
116	
117		const client = createClient(fetch as unknown as typeof globalThis.fetch);
118		const data = await client.request<ArtifactsResult>(ARTIFACTS_QUERY, {
119			projectID: params.projectId,
120			first: PAGE_SIZE,
121			mediaType: mediaType ?? undefined,
122			search: q ? q : undefined,
123			sort,
124			staleness: staleness ?? undefined,
125			phase: phase ?? undefined,
126			prefix: prefix.length > 0 ? prefix : undefined
127		});
128		return {
129			nodeId: params.nodeId,
130			projectId: params.projectId,
131			artifacts: data.artifacts,
132			mediaType,
133			q,
134			groupBy,
135			sort,
136			staleness,
137			phase,
138			prefix,
139			hasGroupByParam
140		};
141	};
