49	async function mockRoutes(page: import('@playwright/test').Page, state: MockState) {
50		await page.route('/graphql', async (route) => {
51			const body = route.request().postDataJSON() as {
52				query: string;
53				variables?: Record<string, string>;
54			};
55			const q = body.query;
56	
57			if (q.includes('NodeInfo')) {
58				await route.fulfill({
59					status: 200,
60					contentType: 'application/json',
61					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
62				});
63				return;
64			}
65			if (q.includes('Projects') && !q.includes('projectID')) {
66				await route.fulfill({
67					status: 200,
68					contentType: 'application/json',
69					body: JSON.stringify({
70						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
71					})
72				});
73				return;
74			}
75			if (q.includes('query Artifacts(') || q.includes('ArtifactsByPath')) {
76				const list = [ARTIFACT_GENERATED, ARTIFACT_PLAIN];
77				const search = body.variables?.search;
78				const filtered = search
79					? list.filter(
80							(a) =>
81								a.title.toLowerCase().includes(String(search).toLowerCase()) ||
82								a.path.toLowerCase().includes(String(search).toLowerCase())
83						)
84					: list;
85				await route.fulfill({
86					status: 200,
87					contentType: 'application/json',
88					body: JSON.stringify({
89						data: {
90							artifacts: {
91								edges: filtered.map((a, i) => ({
92									node: {
93										id: a.id,
94										path: a.path,
95										title: a.title,
96										mediaType: a.mediaType,
97										staleness: a.staleness
98									},
99									cursor: `c${i}`
100								})),
101								pageInfo: { hasNextPage: false, endCursor: null },
102								totalCount: filtered.length
103							}
104						}
105					})
106				});
107				return;
108			}
109			if (q.includes('ArtifactDetail')) {
110				const id = body.variables?.id;
111				const match = [ARTIFACT_GENERATED, ARTIFACT_PLAIN].find((a) => a.id === id);
112				await route.fulfill({
113					status: 200,
114					contentType: 'application/json',
115					body: JSON.stringify({ data: { artifact: match ?? null } })
116				});
117				return;
118			}
119			if (q.includes('RunExists')) {
120				const id = body.variables?.id;
121				await route.fulfill({
122					status: 200,
123					contentType: 'application/json',
124					body: JSON.stringify({
125						data: { run: id === ARTIFACT_GENERATED.generatedBy.runId ? { id } : null }
126					})
127				});
128				return;
129			}
130			if (q.includes('mutation ArtifactRegenerate')) {
131				state.regenerateCalled = true;
132				state.lastArtifactId = body.variables?.artifactId ?? null;
133				await route.fulfill({
134					status: 200,
135					contentType: 'application/json',
136					body: JSON.stringify({
137						data: {
138							artifactRegenerate: { runId: REGENERATE_RUN_ID, status: 'queued' }
139						}
140					})
141				});
142				return;
143			}
144			if (q.includes('Run(') || q.includes('query Run')) {
145				await route.fulfill({
146					status: 200,
147					contentType: 'application/json',
148					body: JSON.stringify({ data: { run: { id: REGENERATE_RUN_ID } } })
149				});
150				return;
151			}
152			await route.continue();
153		});
154	}
